// lakebed-source:shared/game.ts
var MAP_W = 24;
var MAP_H = 18;
var ENCOUNTER_CHANCE = 0.14;
var ENCOUNTER_COOLDOWN = 3;
var ENEMIES = {
  goblin: {
    id: "goblin",
    name: "Goblin Scout",
    maxHp: 28,
    attack: 7,
    defense: 2,
    xp: 12,
    gold: 8,
    color: "#3d7a3d",
    accent: "#8bc34a"
  },
  skeleton: {
    id: "skeleton",
    name: "Bone Warrior",
    maxHp: 36,
    attack: 9,
    defense: 3,
    xp: 18,
    gold: 12,
    color: "#d4cfc4",
    accent: "#8b7355"
  },
  bandit: {
    id: "bandit",
    name: "Highway Bandit",
    maxHp: 42,
    attack: 11,
    defense: 4,
    xp: 24,
    gold: 20,
    color: "#5c4033",
    accent: "#c45c26"
  },
  orc: {
    id: "orc",
    name: "Orc Raider",
    maxHp: 58,
    attack: 14,
    defense: 6,
    xp: 36,
    gold: 28,
    color: "#4a6b3a",
    accent: "#a0522d"
  },
  knight: {
    id: "knight",
    name: "Fallen Knight",
    maxHp: 70,
    attack: 16,
    defense: 9,
    xp: 50,
    gold: 40,
    color: "#4a5568",
    accent: "#c0c0c0"
  },
  dragon: {
    id: "dragon",
    name: "Wyrmling",
    maxHp: 95,
    attack: 20,
    defense: 10,
    xp: 80,
    gold: 75,
    color: "#8b1a1a",
    accent: "#ff6b35"
  }
};
var ENCOUNTER_TABLE = [
  { id: "goblin", weight: 35, minLevel: 1 },
  { id: "skeleton", weight: 25, minLevel: 1 },
  { id: "bandit", weight: 20, minLevel: 2 },
  { id: "orc", weight: 12, minLevel: 3 },
  { id: "knight", weight: 6, minLevel: 4 },
  { id: "dragon", weight: 2, minLevel: 5 }
];
function createPlayer() {
  return {
    name: "Sir Michael",
    level: 1,
    xp: 0,
    xpToNext: 40,
    gold: 0,
    maxHp: 50,
    hp: 50,
    attack: 10,
    defense: 4
  };
}
function createWorld() {
  const map = generateMap(MAP_W, MAP_H);
  return {
    map,
    width: MAP_W,
    height: MAP_H,
    playerX: Math.floor(MAP_W / 2),
    playerY: Math.floor(MAP_H / 2),
    facing: "down",
    stepsSinceFight: ENCOUNTER_COOLDOWN
  };
}
function generateMap(w3, h3) {
  const map = [];
  for (let y3 = 0; y3 < h3; y3++) {
    const row = [];
    for (let x2 = 0; x2 < w3; x2++) {
      const edge = x2 === 0 || y3 === 0 || x2 === w3 - 1 || y3 === h3 - 1;
      if (edge) {
        row.push(Math.random() < 0.55 ? "tree" : "water");
        continue;
      }
      const n2 = Math.random();
      if (n2 < 0.08) row.push("tree");
      else if (n2 < 0.12) row.push("water");
      else if (n2 < 0.18) row.push("stone");
      else if (n2 < 0.28) row.push("path");
      else if (n2 < 0.34) row.push("flower");
      else row.push("grass");
    }
    map.push(row);
  }
  const cx = Math.floor(w3 / 2);
  const cy = Math.floor(h3 / 2);
  for (let dy = -2; dy <= 2; dy++) {
    for (let dx = -2; dx <= 2; dx++) {
      const x2 = cx + dx;
      const y3 = cy + dy;
      if (x2 > 0 && y3 > 0 && x2 < w3 - 1 && y3 < h3 - 1) {
        map[y3][x2] = Math.abs(dx) + Math.abs(dy) <= 1 ? "path" : "grass";
      }
    }
  }
  for (let x2 = 2; x2 < w3 - 2; x2++) {
    if (map[cy][x2] !== "water") map[cy][x2] = "path";
  }
  return map;
}
function isWalkable(tile) {
  return tile === "grass" || tile === "path" || tile === "flower" || tile === "stone";
}
function movePlayer(world, dir) {
  const dx = dir === "left" ? -1 : dir === "right" ? 1 : 0;
  const dy = dir === "up" ? -1 : dir === "down" ? 1 : 0;
  const nx = world.playerX + dx;
  const ny = world.playerY + dy;
  if (nx < 0 || ny < 0 || nx >= world.width || ny >= world.height) {
    return { ...world, facing: dir };
  }
  if (!isWalkable(world.map[ny][nx])) {
    return { ...world, facing: dir };
  }
  return {
    ...world,
    playerX: nx,
    playerY: ny,
    facing: dir,
    stepsSinceFight: world.stepsSinceFight + 1
  };
}
function shouldEncounter(world, tile) {
  if (world.stepsSinceFight < ENCOUNTER_COOLDOWN) return false;
  if (tile === "path") return Math.random() < ENCOUNTER_CHANCE * 0.35;
  if (tile === "grass" || tile === "flower") return Math.random() < ENCOUNTER_CHANCE;
  if (tile === "stone") return Math.random() < ENCOUNTER_CHANCE * 1.2;
  return false;
}
function pickEnemy(level) {
  const eligible = ENCOUNTER_TABLE.filter((e3) => level >= e3.minLevel);
  const total = eligible.reduce((s3, e3) => s3 + e3.weight, 0);
  let roll = Math.random() * total;
  for (const entry of eligible) {
    roll -= entry.weight;
    if (roll <= 0) return ENEMIES[entry.id];
  }
  return ENEMIES.goblin;
}
function startCombat(player, enemyDef) {
  return {
    enemy: {
      id: enemyDef.id,
      name: enemyDef.name,
      maxHp: enemyDef.maxHp,
      hp: enemyDef.maxHp,
      attack: enemyDef.attack,
      defense: enemyDef.defense,
      defending: false,
      xp: enemyDef.xp,
      gold: enemyDef.gold,
      color: enemyDef.color,
      accent: enemyDef.accent
    },
    player: {
      name: player.name,
      maxHp: player.maxHp,
      hp: player.hp,
      attack: player.attack,
      defense: player.defense,
      defending: false
    },
    phase: "player_choose",
    log: [`A wild ${enemyDef.name} appears!`],
    playerDefending: false
  };
}
function calcDamage(atk, def, defending) {
  const mitigation = def + (defending ? Math.floor(def * 1.5) + 2 : 0);
  const raw = atk + Math.floor(Math.random() * 5) - mitigation;
  return Math.max(1, raw);
}
function applyPlayerAttack(combat) {
  const dmg = calcDamage(combat.player.attack, combat.enemy.defense, combat.enemy.defending);
  const hp = Math.max(0, combat.enemy.hp - dmg);
  const log = [...combat.log, `${combat.player.name} strikes for ${dmg}!`];
  if (hp <= 0) {
    return {
      ...combat,
      enemy: { ...combat.enemy, hp: 0, defending: false },
      player: { ...combat.player, defending: false },
      phase: "victory",
      log: [...log, `${combat.enemy.name} is defeated!`],
      playerDefending: false
    };
  }
  return {
    ...combat,
    enemy: { ...combat.enemy, hp, defending: false },
    player: { ...combat.player, defending: false },
    phase: "enemy_act",
    log,
    playerDefending: false
  };
}
function applyPlayerDefend(combat) {
  return {
    ...combat,
    player: { ...combat.player, defending: true },
    phase: "enemy_act",
    log: [...combat.log, `${combat.player.name} raises a shield!`],
    playerDefending: true
  };
}
function tryFlee(combat) {
  if (Math.random() < 0.55) {
    return {
      ...combat,
      phase: "fled",
      log: [...combat.log, "You escape into the woods!"]
    };
  }
  return {
    ...combat,
    phase: "enemy_act",
    log: [...combat.log, "Failed to flee!"],
    playerDefending: false
  };
}
function applyEnemyTurn(combat) {
  if (combat.phase !== "enemy_act") return combat;
  const dmg = calcDamage(combat.enemy.attack, combat.player.defense, combat.playerDefending);
  const hp = Math.max(0, combat.player.hp - dmg);
  const log = [...combat.log, `${combat.enemy.name} hits for ${dmg}!`];
  if (hp <= 0) {
    return {
      ...combat,
      player: { ...combat.player, hp: 0, defending: false },
      phase: "defeat",
      log: [...log, "You have fallen in battle..."],
      playerDefending: false
    };
  }
  return {
    ...combat,
    player: { ...combat.player, hp, defending: false },
    phase: "player_choose",
    log,
    playerDefending: false
  };
}
function awardVictory(player, combat) {
  let { xp, gold, level, maxHp, attack, defense, xpToNext, hp } = player;
  xp += combat.enemy.xp;
  gold += combat.enemy.gold;
  hp = Math.min(maxHp, combat.player.hp + Math.floor(maxHp * 0.1));
  while (xp >= xpToNext) {
    xp -= xpToNext;
    level += 1;
    maxHp += 12;
    attack += 3;
    defense += 2;
    hp = maxHp;
    xpToNext = Math.floor(xpToNext * 1.35);
  }
  return { ...player, xp, gold, level, maxHp, attack, defense, xpToNext, hp };
}
function syncPlayerHp(player, combat) {
  return { ...player, hp: combat.player.hp };
}
function healAtCamp(player) {
  return { ...player, hp: player.maxHp };
}

